mapper.select:
SELECT
    img_path AS imgPath,
    img_name AS imgName,
    sort_ord AS sortOrd,
    photo_gb AS photoGb,
    is_main AS isMain
FROM pothole_photo
WHERE report_no = #{reportNo}
  AND photo_gb = #{photoGb}
  AND sort_ord = #{sortOrd}

SELECT sort_ord
FROM pothole_photo
WHERE report_no = #{reportNo}
  AND photo_gb  = #{photoGb}
ORDER BY sort_ord ASC

mapper.delete:
DELETE FROM pothole_photo
WHERE report_no = #{reportNo}
  AND photo_gb  = #{photoGb}
  AND sort_ord  = #{sortOrd}

mapper.update:
UPDATE pothole_photo
SET is_main = 'N'
WHERE report_no = #{reportNo}
  AND photo_gb = #{photoGb}

UPDATE pothole_photo
SET is_main = 'Y'
WHERE report_no = #{reportNo}
  AND photo_gb  = #{photoGb}
  AND sort_ord  = #{sortOrd}

UPDATE pothole_photo
SET sort_ord = #{tempSortOrd}
WHERE report_no = #{reportNo}
  AND photo_gb  = #{fromPhotoGb}
  AND sort_ord  = #{fromSortOrd}

UPDATE pothole_photo
SET photo_gb = #{toPhotoGb},
    sort_ord = #{toSortOrd}
WHERE report_no = #{reportNo}
  AND photo_gb  = #{fromPhotoGb}
  AND sort_ord  = #{tempSortOrd}

UPDATE pothole_photo
SET img_path = #{imgPath},
    img_name = #{imgName}
WHERE report_no = #{reportNo}
  AND photo_gb = #{photoGb}
  AND sort_ord = #{sortOrd}
